# ============================================================
# Crash logging -- MUST be installed before anything that can fail
# (module imports, path setup, etc.) or a boot-time failure dies
# silently to stderr with nothing for muOS to show/save. This bit
# muOS Favs Sorter (Fix 11/13) and cost real debugging time -- see
# note below on why the epub_engine/mini_jpeg imports were moved
# below this block instead of staying up with the stdlib imports.
# ============================================================
CRASH_LOG = "/tmp/picoreader_crash.log"
# v26.07.20.18 (Kaleb's request -- log hygiene): caps CRASH_LOG at 1MB.
# Previously this just appended forever with no rotation -- unbounded
# growth on a device with limited storage over months of use. Simple
# truncate-on-cap rather than real rotation (no .1/.2 history) --
# crash-log history beyond "the most recent ~1MB" isn't valuable enough
# here to justify the extra complexity.
LOG_CAP_BYTES = 1024 * 1024


def _boot_log(msg):
    try:
        if os.path.exists(CRASH_LOG) and os.path.getsize(CRASH_LOG) > LOG_CAP_BYTES:
            os.remove(CRASH_LOG)
        with open(CRASH_LOG, "a") as f:
            f.write(msg)
    except Exception:
        pass


def _excepthook(exc_type, exc_value, tb):
    import traceback
    _boot_log("\n--- UNCAUGHT EXCEPTION ---\n")
    _boot_log("".join(traceback.format_exception(exc_type, exc_value, tb)))
    _boot_log("--- END ---\n")


sys.excepthook = _excepthook

# Also catch exceptions raised on background threads (ImageLoader's worker
# thread etc.) -- threading.excepthook is a SEPARATE hook from sys.excepthook
# on Python 3.8+, so without this, a thread-level crash would never reach
# picoreader_crash.log even though sys.excepthook is installed above.
def _thread_excepthook(args):
    import traceback
    _boot_log("\n--- UNCAUGHT THREAD EXCEPTION ---\n")
    _boot_log(f"thread: {args.thread.name}\n")
    _boot_log("".join(traceback.format_exception(args.exc_type, args.exc_value, args.exc_traceback)))
    _boot_log("--- END ---\n")


threading.excepthook = _thread_excepthook

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
try:
    import epub_engine
    from epub_engine import EpubDocument, ReaderState, TocEntry
    from mini_jpeg import decode_jpeg as _decode_jpeg_pure_python, peek_jpeg_size
except Exception:
    import traceback
    _boot_log("\n--- IMPORT FAILURE (epub_engine / mini_jpeg) ---\n")
    _boot_log(traceback.format_exc())
    _boot_log("--- END ---\n")
    sys.exit(1)

# v0.1.80 -- native_image.py is OPTIONAL, same spirit as the downloader
# plugins below: the app must work identically whether it's present/
# loadable or not. It's a ctypes bridge to the system's libSDL2_image
# (confirmed present on the RG CubeXX-H's muOS build at /usr/lib --
# Kaleb found it via SFTP file browsing), used to decode images at real C
# speed instead of mini_jpeg.py's pure-Python JPEG-only decoder. See
# native_image.py's own module docstring for the full story (this is the
# actual fix for the image-decode freeze bug, not just a speed
# optimization -- a C decode doesn't hold Python's GIL the whole time the
# way mini_jpeg.py's decode loop does). mini_jpeg.py is NOT being
# removed: if native_image fails to load OR fails to decode a specific
# file for any reason, decode_jpeg() below falls straight back to the
# pure-Python path, per-call, silently.
# v0.1.146: renamed from native_jpeg.py -- Kaleb asked for a name that's
# more obviously accurate now that this handles more than JPEG (v0.1.145
# generalized it to every SDL2_image format: JPG/PNG/TIF/WEBP/JXL/AVIF).
try:
    import native_image
    # v26.07.14.13 BUG FIX (Kaleb's report: Pre-render/Disk-Cache toggle
    # rows in Settings showed up on a "second boot" when they should stay
    # hidden -- native decode is genuinely available on his device both
    # times). Root cause: native_image._init() (the actual libSDL2_image
    # load attempt) used to only run LAZILY, from inside
    # decode_image_native(), which only fires on the first real image
    # decode. Every check of native_image.available elsewhere in this file
    # (this hide condition, the Toggle Disk Cache guard, etc.) reads the
    # module-level `available` flag directly -- so if Settings gets opened
    # before any book with images is viewed in that session, `available`
    # is still stuck at its False default, and every one of those checks
    # sees the library as absent even though it isn't. Calling _init()
    # eagerly here, right after import, makes availability known before
    # the very first frame renders, regardless of what screen gets opened
    # first or whether an image is ever decoded that session.
    native_image._init()
except Exception:
    native_image = None

# v26.07.20.03: same optional-native-module pattern as native_image above.
# native_video.py adds JW.org video playback (stream or downloaded-file)
# via muOS's native ffplay + a self-contained uinput-based gamepad
# translator -- see that file's own docstring for the full design
# rationale (why uinput instead of bundling gptokeyb2/depending on
# PortMaster). No SDL2_image-style native/fallback split here since
# there's no pure-Python video decode to fall back to -- if this import
# fails (missing ffplay, no /dev/uinput access, etc.) the feature is
# simply unavailable this session; every call site checks
# `native_video is not None` first and hides/disables the relevant UI
# entry rather than erroring.
try:
    import native_video
except Exception:
    native_video = None


def decode_jpeg(jpeg_bytes, scale_n=4):
    """Drop-in replacement for mini_jpeg.decode_jpeg() with the identical
    (rgb_bytes, w, h) contract. Tries the native libSDL2_image path first
    (fast, doesn't hold the GIL); falls back to the pure-Python decoder
    on any failure -- missing library, decode error, anything. This
    function is what every other call site in this file uses; neither
    ImageLoader nor anything else needs to know or care which decoder
    actually ran. NOTE: still named decode_jpeg (not decode_image) --
    kept as-is in v0.1.146's rename since every call site already treats
    it as "the" image decode entry point regardless of format, so
    renaming this specific one would only add churn across the file
    without changing behavior; the module/function names that actually
    described a JPEG-only assumption (native_jpeg.py, decode_jpeg_native)
    were the misleading ones and those did get renamed."""
    if native_image is not None:
        try:
            return native_image.decode_image_native(jpeg_bytes, scale_n=scale_n)
        except Exception as e:
            _boot_log(f"native_image decode failed, falling back to mini_jpeg: {e}\n")
    return _decode_jpeg_pure_python(jpeg_bytes, scale_n=scale_n)

# ============================================================
# Optional downloader plugins -- unlike epub_engine/mini_jpeg above,
# these are genuinely OPTIONAL: the app must work identically whether
# zero, one, or both files are present. Each is a self-contained module
# (see gutenberg_fetch.py's docstring for the plugin contract every
# downloader module must implement: PLUGIN_NAME, list_items(), download()).
# A plugin failing to import (missing file, or a bug inside it) is
# swallowed and logged, never fatal -- the Library/Storage screens check
# DOWNLOAD_PLUGINS and simply don't show a "Download Books" option if
# it's empty, rather than crashing or showing a broken menu item.
DOWNLOAD_PLUGINS = []
for _plugin_mod_name in ("gutenberg_fetch", "jw_fetch"):
    try:
        _mod = __import__(_plugin_mod_name)
        DOWNLOAD_PLUGINS.append(_mod)
    except Exception:
        _boot_log(f"optional plugin '{_plugin_mod_name}' not loaded (this is fine if the "
                   f"file isn't present): {sys.exc_info()[1]}\n")

# v0.1.90: direct reference to jw_fetch specifically (not just "any
# plugin in DOWNLOAD_PLUGINS") for the video-download feature, since
# video support is JW-specific (gutenberg_fetch has no videos) and only
# exists if jw_fetch has the v0.1.90 list_video_items()/download_video()
# functions -- older jw_fetch.py builds won't have them, so this checks
# for the attribute rather than assuming any jw_fetch import supports it.
JW_PLUGIN = next((m for m in DOWNLOAD_PLUGINS if m.__name__ == "jw_fetch"), None)
JW_VIDEO_SUPPORTED = bool(JW_PLUGIN and hasattr(JW_PLUGIN, "list_video_items"))

# ============================================================
# Paths
# ============================================================
APP_DIR = os.path.dirname(os.path.abspath(__file__))


def find_books_dir():
    """SD1/SD2-aware location for muOS's shared 'Book Reader' content
    folder -- same principle/candidates as jw_fetch.py's
    find_movies_dir()/find_music_dir(). muos.dev documents "Book Reader"
    as an existing muOS system (served by the third-party mReader core)
    with its own ROMS/Book Reader content folder; sharing it rather
    than PicoReader's own app dir puts books where muOS's other content
    lives and would let PicoReader register as an alt core for that
    system later. Checks /mnt/union (muOS's universal SD1+SD2 merged
    mount, checked first), then /mnt/sdcard, then /mnt/mmc; falls back
    to creating the /mnt/union path if none exist yet.

    No old-location migration on a folder change -- bookmarks are keyed
    by full file path (see load_bookmarks/save_bookmarks), so moving
    this folder orphans progress recorded under the old path. Fine for
    this personal/testing setup; worth a real migration step (rewrite
    matching bookmarks.json keys) if that ever needs to be preserved."""
    candidates = [
        "/mnt/union/ROMS/Book Reader",
        "/mnt/sdcard/ROMS/Book Reader",
        "/mnt/mmc/ROMS/Book Reader",
    ]
    for path in candidates:
        if os.path.isdir(path):
            return path
    fallback = candidates[0]
    try:
        os.makedirs(fallback, exist_ok=True)
    except OSError:
        pass
    return fallback


LIBRARY_DIR = os.environ.get("EPUB_LIBRARY_DIR", find_books_dir())
DATA_DIR = os.path.join(APP_DIR, "data")
BOOKMARKS_PATH = os.path.join(DATA_DIR, "bookmarks.json")
SETTINGS_PATH = os.path.join(DATA_DIR, "settings.json")
CUSTOM_THEME_PATH = os.path.join(DATA_DIR, "custom_theme.json")  # v26.07.15.19:
# holds at most ONE saved random theme (Kaleb's choice -- "only keep the
# most recent one"). Separate small file rather than a settings.json key
# so it's trivially backup-able/inspectable on its own.
LIBRARY_CACHE_PATH = os.path.join(DATA_DIR, "library_cache.json")
PINNED_PATH = os.path.join(DATA_DIR, "pinned.json")
ANCHOR_CACHE_DIR = os.path.join(DATA_DIR, "anchor_cache")
IMG_CACHE_DIR = os.path.join(DATA_DIR, "img_cache")
# Disk cache for wrapped (laid-out) page results -- narrow on purpose,
# only for pages over PRERENDER_THRESHOLD below, not a general-purpose
# cache like IMG_CACHE_DIR.
WRAP_CACHE_DIR = os.path.join(DATA_DIR, "wrap_cache")

# Three thresholds tune how "big" pages are handled, all calibrated from
# real on-device timing (Kaleb's RG CubeXX-H): cold text-wrap runs
# ~8.7 microseconds/char, warm disk-cache reads run ~900,000 bytes/sec.
# "Big enough to need a screen" and "big enough to cache forever" are
# deliberately separate questions -- see each constant below.

# Pages over this many characters show a live-percentage loading screen
# during the synchronous cold wrap (draw_reader()). ~115,000 chars is
# about 1.0s -- anything faster than that should feel instant, no screen.
LARGE_PAGE_LOADING_THRESHOLD = 115_000

# Pages over this many characters ALSO get their wrapped result written
# permanently to WRAP_CACHE_DIR, so the cost is paid once per (book,
# page, font size) ever, not every visit. ~90,000 chars is about 0.8s --
# intentionally lower than the loading-screen bar above, since a page
# can be worth caching forever without being slow enough to need a
# spinner. The extreme-page RAM pool this feeds (self._EXTREME_POOL_MAX
# = 3, App.__init__) caps how many such pages stay resident at once,
# independent of how many a book has.
PRERENDER_THRESHOLD = 90_000

# Pages whose WRAP_CACHE_DIR file exceeds this many bytes show their own

# v26.07.14.16 (Kaleb's request): pages below LARGE_PAGE_LOADING_THRESHOLD
# never showed ANY loading feedback before the synchronous parse+wrap
# below -- fine for genuinely small pages, but LARGE_PAGE_LOADING_
# THRESHOLD itself (~115,000 bytes) is calibrated to ~1.0s on DEV
# hardware; applying this project's own confirmed ~4.1x dev-to-device
# scaling factor, that's roughly ~4.1s on the real ARM device already --
# meaning a page well under this threshold in raw bytes can still cost
# multiple real seconds on-device with zero visual feedback, which is
# exactly the "1-5 second delay, page still just freezes" gap Kaleb
# reported even after the extreme-page progressive/chunked work. This
# lower threshold gates a lightweight toast (NOT the full-screen
# "Opening page..." treatment) for that in-between size range. VALUE IS
# AN ESTIMATE, NOT YET CONFIRMED ON REAL HARDWARE -- unlike this
# project's other thresholds (all derived from real on-device timing),
# this one is a starting guess pending Kaleb's actual test; adjust once
# real numbers come back.
MEDIUM_PAGE_TOAST_THRESHOLD = 30_000

# "Loading cached page..." screen when read back on a later visit --
# separate from the two thresholds above because warm-load cost is disk
# I/O + unpickle (scales with serialized bytes), not text length.
# ~900,000 bytes is about 1.0s. Below it, the read happens silently.
WARM_CACHE_LOADING_THRESHOLD = 900_000

# On-disk wrap-cache format v2 (WARM_CACHE_MAGIC): chunked instead of one
# single pickle blob, so revisiting an already-cached extreme page grows
# on-screen progressively instead of blocking for the whole read (was a
# real ~7-8s freeze on Enjoy Life Forever's Track Your Bible Reading).
# v1 (pre-v26.07.13.15, unchunked) cache files fail the magic check and
# fall through to the normal fail-soft rebuild path.
WARM_CACHE_MAGIC = b"PRWC2\x00"
# Max lines per on-disk chunk (v26.07.13.31: this is a ceiling, not a
# fixed size -- see WARM_LOAD_MIN_CHUNKS below for why). Fewer, bigger
# chunks mean fewer file-read + pickle.loads() calls; warm-load's read
# already runs on a background thread, so chunk size here is about I/O
# efficiency, not input responsiveness. Governs the ON-DISK FORMAT
# itself (_save_wrap_to_disk()) -- only newly-written cache files pick
# up a changed value; existing files keep their original chunking.
WARM_LOAD_CHUNK_LINES = 15000
# BUG FIX (Kaleb's report: warm-load "doesn't load until a button is
# pressed"): a page with fewer total lines than WARM_LOAD_CHUNK_LINES
# collapsed to ONE chunk, so nothing appeared until that single
# pickle.loads() finished -- looked identical to being stuck. This
# floors the chunk COUNT so small/medium extreme pages always show real
# progressive growth; WARM_LOAD_MIN_CHUNK_LINES then floors the chunk
# SIZE so a page just over PRERENDER_THRESHOLD doesn't get sliced into
# dozens of framing-overhead-dominated chunks to hit that count.
WARM_LOAD_MIN_CHUNKS = 6
WARM_LOAD_MIN_CHUNK_LINES = 500

# How often the main loop does a FULL visible render (all on-screen
# lines, hint bar, toast) while a build progresses but nothing else
# needs a redraw -- see advance_progressive_builds()'s docstring. Wrap/
# warmload/bg-prerender stepping still happens every loop iteration
# regardless; this only throttles how often the SCREEN redraws.
# Tuned against real on-device timing on the Track Your Bible Reading
# build: render overhead turned out to be a much smaller fraction of
# real-device cost than dev-hardware profiling suggested (the actual
# SDL_ttf glyph-measurement work dominates) -- diminishing returns above
# ~2.0s, current value chosen to stay visibly "alive" during a real
# multi-minute build without adding meaningful overhead.
READER_BUILD_RENDER_THROTTLE = 5.0

# COLD_WRAP_RESPONSIVE_SECONDS (old fixed-window slice-widening) is
# superseded by the COLD_WRAP_RAMP_SECONDS curve below and unread --
# left defined for reference only.
COLD_WRAP_RESPONSIVE_SECONDS = 4.0

# Adaptive cold-wrap slice size: seconds of genuine idle (no real
# button press) it takes the per-slice time budget to ramp from
# COLD_WRAP_INITIAL_SLICE_SECONDS up to COLD_WRAP_FALLBACK_SLICE_SECONDS,
# via a single smooth quadratic curve (budget(t) = INITIAL +
# (t/RAMP_SECONDS)**2 * (FALLBACK - INITIAL), clamped to t <=
# RAMP_SECONDS -- see cold_wrap_slice_budget() below). Resets to 0 the
# instant any real input happens, no matter how deep into the build, so
# responsiveness recovers on touch rather than only during a fixed
# opening window. Both foreground cold-wrap and the background
# prerender queue share this same formula, keyed off app._last_input_time.
COLD_WRAP_RAMP_SECONDS = 4.0

# Sample points at INITIAL=100ms: t=0s->100ms, t=1.0s->~219ms,
# t=2.0s->~575ms, t=3.0s->~1169ms, t=4.0s->2000ms (FALLBACK).
# CONFIRMED ON REAL HARDWARE (Kaleb, cold-loading Enjoy Life Forever's
# "Track Your Bible Reading", ~4.5M chars, the app's known worst case):
# ~54s total; button-press sound reliably plays for presses made during
# the wait, giving audible confirmation a press registered mid-build.
COLD_WRAP_INITIAL_SLICE_SECONDS = 0.100
# Slice size once the ramp is fully idle-warmed -- bigger slices give
# real on-device speed gains, but fully unbounded (one shot to finish)
# would freeze all input for the back half of a build; this keeps a
# finite checkpoint interval. CONFIRMED on real device (Track Your
# Bible Reading): ~51s idle/no input vs ~52s with active button presses
# throughout -- the ~1s responsiveness cost is negligible, so 2.0s is
# the right fallback ceiling.
COLD_WRAP_FALLBACK_SLICE_SECONDS = 2.0


def cold_wrap_slice_budget(since_input):
    """Returns the per-slice time budget (seconds) for cold-wrap/
    background-prerender chunked stepping, given seconds of genuine
    idle time (since_input). Single choke point for the ramp curve --
    both the foreground cold-wrap branch and _step_bg_prerender() call
    this instead of each computing the ramp formula themselves, so the
    two paths can't drift out of sync. Single smooth quadratic curve
    (v26.07.16.13) -- see COLD_WRAP_INITIAL_SLICE_SECONDS's comment
    above for the shape/history."""
    frac = min(1.0, since_input / COLD_WRAP_RAMP_SECONDS)
    return COLD_WRAP_INITIAL_SLICE_SECONDS + (frac ** 2) * (
        COLD_WRAP_FALLBACK_SLICE_SECONDS - COLD_WRAP_INITIAL_SLICE_SECONDS)

# TRIED AND REVERTED: zlib-compressing the on-disk wrap-cache blob.
# Dev-hardware profiling suggested a net win (~27% of original size),
# but real on-device testing showed the opposite -- warm-open got ~1s
# WORSE per read, not better. The real ARM CPU's decompress cost exceeds
# the I/O savings it buys back. Do not re-attempt without a way to
# profile actual decompress cost on the real device first.

# Deliberately a sibling of library/ and data/, not buried inside data/ --
# the whole point of a backup is being easy to find and copy off the
# device (SD card swap, USB, another file manager) without having to know
# it's hiding inside the app's internal data folder.
BACKUP_DIR = os.path.join(APP_DIR, "backups")
# v0.1.63: unlike CRASH_LOG (/tmp -- wiped on reboot, only useful over SSH
# same session), this lives in DATA_DIR so it survives reboots and can be
# pulled off the SD card later. Records non-fatal render oddities (e.g. a
# spine page that parsed to zero text/images -- see log_render_issue()) --
# things that aren't crashes but are worth knowing about after the fact.
RENDER_LOG_PATH = os.path.join(DATA_DIR, "render_issues.log")


def book_id(book_path):
    """Stable per-book identifier, deterministic from the path alone (so
    it can be recomputed even for a book that's since been deleted, e.g.
    to find and purge its orphaned cache files). Same derivation the
    anchor cache already used, now also reused to namespace image-cache
    keys -- without this, two different books that happen to share an
    internal image path (common in EPUB packaging, e.g. both using
    "OEBPS/images/cover.jpg") would silently collide in the shared
    ImageLoader and show each other's cached image."""
    return hashlib.sha1(book_path.encode()).hexdigest()[:16]

