COL_BG = COL_PANEL = COL_TEXT = COL_DIM = None
COL_LINK = COL_LINK_SEL = COL_HINT_BG = COL_HINT_TEXT = None
COL_ACCENT = COL_MENU_SEL_BG = COL_WARNING = None

THEME_INDEX = 0

# v26.07.17.10 (Kaleb's request): Night Mode -- a popup-menu toggle that
