_IMG_DIM_ALPHA_CURRENT = None
_IMG_DIM_ALPHA_FROM = 0.0
_IMG_DIM_ALPHA_TO = 0.0
_IMG_DIM_TRANS_START = 0.0
_IMG_DIM_TRANS_DURATION = 0.18

